func configDefault(config ...Config) Config {

	if len(config) < 1 {
		return ConfigDefault
	}

	cfg := config[0]

	if len(cfg.IndexNames) == 0 {
		cfg.IndexNames = ConfigDefault.IndexNames
	}

	if cfg.CacheDuration == 0 {
		cfg.CacheDuration = ConfigDefault.CacheDuration
	}

	return cfg
}
